import{_ as a,c as t,o as s,ag as o}from"./chunks/framework.D4Vqf8I7.js";const l=JSON.parse('{"title":"Steam","description":"","frontmatter":{},"headers":[],"relativePath":"docs/wi/games/steam.md","filePath":"docs/wi/games/steam.md","lastUpdated":1784547278000}'),r={name:"docs/wi/games/steam.md"};function m(i,e,d,p,c,n){return s(),t("div",null,e[0]||(e[0]=[o('<h1 id="steam" tabindex="-1">Steam <a class="header-anchor" href="#steam" aria-label="Permalink to &quot;Steam&quot;">​</a></h1><p><a href="https://www.reddit.com/r/SteamOS/comments/1ue3p8x/steamos_3810_official_iso_is_out/" target="_blank" rel="noreferrer">https://www.reddit.com/r/SteamOS/comments/1ue3p8x/steamos_3810_official_iso_is_out/</a></p><p>steamdeck-images.steamos.cloud/recovery/</p><h2 id="зависание-при-старте" tabindex="-1">Зависание при старте <a class="header-anchor" href="#зависание-при-старте" aria-label="Permalink to &quot;Зависание при старте&quot;">​</a></h2><p>Иногда, когда Steam зависает, он пытается принудительно проверить наличие обновлений, что всегда заканчивается неудачей из-за отсутствия интернета. Чтобы предотвратить запуск программы обновления, создайте в той же папке, что и исполняемый файл Steam, файл с именем &quot;steam.cfg&quot; со следующим содержимым:</p><p>BootStrapperInhibitAll=enable</p><h2 id="sdepkdm" tabindex="-1">sdepkdm <a class="header-anchor" href="#sdepkdm" aria-label="Permalink to &quot;sdepkdm&quot;">​</a></h2><p>Если вы откроете файл appmanifest игры и измените значение параметра &quot;StateFlags&quot; на &quot;4&quot;, Steam увидит, что игра полностью обновлена. Таким образом, если вы хотите/нуждаетесь в игре в автономном режиме, но обновление так и не завершилось, вы можете избежать необходимости завершать загрузку этого обновления до тех пор, пока не сможете снова подключиться к сети.</p><p>Если вы не подключены к интернету, после внесения изменений в этот текстовый файл, обновления больше не будут вас беспокоить. Но как только вы подключитесь к интернету, система поймет, что что-то не так.</p>',9)]))}const u=a(r,[["render",m]]);export{l as __pageData,u as default};
